import { useState, useRef, useEffect } from "react";

function App() {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const bottomRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const sendMessage = async () => {
    if (!input.trim()) return;

    const userMessage = { role: "user", content: input };
    setMessages((prev) => [...prev, userMessage]);
    setInput("");
    setLoading(true);

    const response = await fetch("http://127.0.0.1:8000/chat", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        session_id: "student1",
        message: input,
      }),
    });

    const data = await response.json();
    const botMessage = { role: "assistant", content: data.reply };
    setMessages((prev) => [...prev, botMessage]);
    setLoading(false);
  };

  return (
    <div style={styles.page}>

      <div style={styles.topBar}>
        <div style={styles.dot} />
        <span style={styles.topBarText}>FAST-NUCES Islamabad</span>
      </div>

      <div style={styles.chatArea}>
        {messages.length === 0 && (
          <div style={styles.emptyState}>
            <p style={styles.emptyTitle}>How can I help you today?</p>
            <p style={styles.emptySubtitle}>
              Ask me about admissions, fee, courses, or campus life.
            </p>
            <div style={styles.suggestions}>
              {[
                "What is the fee structure?",
                "How do I register for courses?",
                "Tell me about societies at FAST",
              ].map((s, i) => (
                <button
                  key={i}
                  style={styles.suggestion}
                  onClick={() => setInput(s)}
                >
                  {s}
                </button>
              ))}
            </div>
          </div>
        )}

        {messages.map((msg, index) => (
          <div
            key={index}
            style={
              msg.role === "user"
                ? styles.userRow
                : styles.botRow
            }
          >
            {msg.role === "assistant" && (
              <div style={styles.avatar}>F</div>
            )}
            <div
              style={
                msg.role === "user"
                  ? styles.userBubble
                  : styles.botBubble
              }
            >
              {msg.content}
            </div>
          </div>
        ))}

        {loading && (
          <div style={styles.botRow}>
            <div style={styles.avatar}>F</div>
            <div style={styles.botBubble}>
              <span style={styles.typing}>● ● ●</span>
            </div>
          </div>
        )}

        <div ref={bottomRef} />
      </div>

      <div style={styles.inputRow}>
        <input
          style={styles.input}
          type="text"
          placeholder="Type your question..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && sendMessage()}
        />
        <button
          style={loading ? styles.buttonDisabled : styles.button}
          onClick={sendMessage}
          disabled={loading}
        >
          ↑
        </button>
      </div>

      <p style={styles.footer}>
        FAST Assistant may make mistakes. Verify important info with your department.
      </p>

    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    background: "#fafafa",
    display: "flex",
    flexDirection: "column",
    fontFamily: "'Segoe UI', sans-serif",
    maxWidth: "760px",
    margin: "0 auto",
  },
  topBar: {
    display: "flex",
    alignItems: "center",
    gap: "10px",
    padding: "18px 24px",
    borderBottom: "1px solid #ebebeb",
    background: "#fff",
  },
  dot: {
    width: "10px",
    height: "10px",
    borderRadius: "50%",
    background: "#2ecc71",
  },
  topBarText: {
    fontSize: "15px",
    fontWeight: "600",
    color: "#1a1a1a",
    letterSpacing: "0.3px",
  },
  chatArea: {
    flex: 1,
    padding: "28px 24px",
    overflowY: "auto",
    minHeight: "calc(100vh - 160px)",
  },
  emptyState: {
    textAlign: "center",
    marginTop: "100px",
  },
  emptyTitle: {
    fontSize: "24px",
    fontWeight: "600",
    color: "#1a1a1a",
    marginBottom: "8px",
  },
  emptySubtitle: {
    fontSize: "15px",
    color: "#888",
    marginBottom: "32px",
  },
  suggestions: {
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    gap: "10px",
  },
  suggestion: {
    background: "#fff",
    border: "1px solid #e0e0e0",
    borderRadius: "20px",
    padding: "10px 20px",
    fontSize: "14px",
    color: "#444",
    cursor: "pointer",
    transition: "all 0.2s",
  },
  userRow: {
    display: "flex",
    justifyContent: "flex-end",
    marginBottom: "16px",
  },
  botRow: {
    display: "flex",
    alignItems: "flex-start",
    gap: "10px",
    marginBottom: "16px",
  },
  avatar: {
    width: "32px",
    height: "32px",
    borderRadius: "50%",
    background: "#1a3c5e",
    color: "white",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontSize: "14px",
    fontWeight: "bold",
    flexShrink: 0,
  },
  userBubble: {
    background: "#1a3c5e",
    color: "white",
    padding: "12px 16px",
    borderRadius: "18px 18px 4px 18px",
    maxWidth: "70%",
    fontSize: "14px",
    lineHeight: "1.6",
  },
  botBubble: {
    background: "#fff",
    border: "1px solid #ebebeb",
    color: "#1a1a1a",
    padding: "12px 16px",
    borderRadius: "4px 18px 18px 18px",
    maxWidth: "70%",
    fontSize: "14px",
    lineHeight: "1.6",
  },
  typing: {
    color: "#888",
    letterSpacing: "4px",
    fontSize: "12px",
  },
  inputRow: {
    display: "flex",
    gap: "10px",
    padding: "16px 24px",
    borderTop: "1px solid #ebebeb",
    background: "#fff",
  },
  input: {
    flex: 1,
    padding: "12px 18px",
    borderRadius: "24px",
    border: "1px solid #e0e0e0",
    fontSize: "14px",
    outline: "none",
    background: "#fafafa",
    color: "#1a1a1a",
  },
  button: {
    width: "44px",
    height: "44px",
    borderRadius: "50%",
    background: "#1a3c5e",
    color: "white",
    border: "none",
    fontSize: "18px",
    cursor: "pointer",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  },
  buttonDisabled: {
    width: "44px",
    height: "44px",
    borderRadius: "50%",
    background: "#ccc",
    color: "white",
    border: "none",
    fontSize: "18px",
    cursor: "not-allowed",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  },
  footer: {
    textAlign: "center",
    fontSize: "12px",
    color: "#aaa",
    padding: "10px",
    background: "#fff",
  },
};

export default App;
